class Node:
    def __init__(self, key, value):
        self.key = key
        self.value = value
        self.count = 1
        self.prev = None
        self.next = None

class DoublyLinkedList:
    def __init__(self):
        self.head = Node(0, 0)
        self.tail = Node(0, 0)
        self.head.next = self.tail
        self.tail.prev = self.head

    def remove(self, node):
        node.prev.next = node.next
        node.next.prev = node.prev

    def add_first(self, node):
        node.prev = self.head
        node.next = self.head.next
        self.head.next.prev = node
        self.head.next = node

    def pop_first(self):
        node = self.head.next
        self.remove(node)
        return node

class LFUCache:

    def __init__(self, capacity: int):
        self.capacity = capacity
        self.size = 0
        self.min_count = 0
        self.key_node = defaultdict(Node)
        self.count_node = defaultdict(DoublyLinkedList)

    def get(self, key: int) -> int:
        if key not in self.key_node:
            return -1
        node = self.key_node[key]
        self._update_count(node)
        return node.value

    def put(self, key: int, value: int) -> None:
        if self.capacity == 0:
            return
        if key in self.key_node:
            self.key_node[key].value = value
            self._update_count(self.key_node[key])
        else:
            if self.size == self.capacity:
                node = self.count_node[self.min_count].pop_first()
                del self.key_node[node.key]
                self.size -= 1
            node = Node(key, value)
            self.key_node[key] = node
            self.count_node[1].add_first(node)
            self.min_count = 1
            self.size += 1

    def _update_count(self, node):
        self.count_node[node.count].remove(node)
        node.count += 1
        self.count_node[node.count].add_first(node)
        if self.min_count == node.count - 1:
            self.min_count += 1
